mapper.select:
SELECT cash_balance
FROM user_account
WHERE user_seq = #{userSeq}

mapper.update:
UPDATE user_account
Set cash_balance = cash_balance + #{amount}
WHERE user_seq = #{userSeq}

mapper.select:
SELECT quantity
FROM  mock_portfolio JOIN stock_master ON mock_portfolio.stock_seq =stock_master.stock_seq
WHERE user_seq = #{userSeq} AND stock_code= #{stockCode}

mapper.insert:
INSERT INTO mock_portfolio(user_seq, stock_seq, quantity, avg_price) VALUES (#{userSeq}, #{stockSeq}, #{tradeQuantity}, #{tradePrice}) ON DUPLICATE KEY UPDATE
avg_price = (avg_price * quantity + #{tradePrice} * #{tradeQuantity}) / (quantity + #{tradeQuantity}), quantity = quantity + #{tradeQuantity}
avg_price = avg_price, quantity = quantity - #{tradeQuantity}
avg_price = 0, quantity = quantity
